def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        base_score = 0.0
        complexity = 1.0
        decay = 1.0
        boost = 1.0
        modifier = 1.0
        feedback = 0.0
        cache = {}
        for a in range(1, 15):
            for b in range(1, 10):
                key = (a, b)
                if key in cache:
                    value = cache[key]
                else:
                    val1 = np.tanh((item + a*b) / (cap + 1))
                    val2 = np.cos(ratio * a * b)
                    val3 = np.exp(-abs(cap - item*(a+b)) / (cap + 1))
                    value = (val1 * val2 + val3) / (a + b + 1)
                    cache[key] = value
                if (a * b + cap) % 11 == 0:
                    value *= 1.07
                elif (cap - a * b) % 9 == 0:
                    value *= 0.93
                base_score += value * complexity
            if a % 4 == 0:
                complexity *= 1.03 + 0.005 * a
            elif a % 5 == 0:
                complexity *= 0.97 - 0.004 * a
            if ratio > 0.7 and a % 3 == 0:
                boost *= 1.12 + 0.015 * a
            elif ratio < 0.3 and a % 2 == 1:
                decay *= 0.88 - 0.009 * a
            if (cap * a + a*a) % 8 == 0:
                modifier *= 1.05
            elif (cap + a*a) % 6 == 0:
                modifier *= 0.95
            if a == 7:
                for c in range(1, 7):
                    delta = cap - item * (c**3)
                    if delta > 0:
                        if delta % (c + 1) == 0:
                            feedback += np.cbrt(delta) / (c + 2)
                        else:
                            feedback -= np.log1p(abs(delta)) / (c + 3)
                    else:
                        feedback -= abs(delta) ** 1.5 / (c + 4)
            if a % 6 == 1 and (cap + a) % (a + 2) == 0:
                feedback += np.sin(a * ratio * 2) * 0.7
        total_score = (base_score + feedback * 0.9) * boost * decay * modifier
        if total_score <= 0:
            priorities[i] = -total_score * (np.log1p(cap + item) + np.cbrt(cap))
        else:
            if cap > item * 5:
                priorities[i] = -total_score / (np.cbrt(cap) + 1.5) * (1 + ratio * 0.9)
            elif cap > item * 2:
                priorities[i] = -total_score / (cap + 5) * np.exp(-ratio**1.5)
            else:
                priorities[i] = -total_score / (cap + 10) * (1 + np.sin(ratio * np.pi))
        if ratio > 0.9:
            priorities[i] *= 1.18
        elif ratio < 0.1:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.96
        elif cap % 5 == 0:
            priorities[i] *= 1.04
        else:
            priorities[i] *= 1.01
        if item % 2 == 0:
            priorities[i] *= 0.99
        else:
            priorities[i] *= 1.03
    return priorities
